One way to achieve this is to use the `GetLastError` function along with `FormatMessage` to retrieve and format the error message associated with the last error. Here's an updated example with error handling messages:

```cpp
#include <windows.h>
#include <iostream>

int main(int argc, char* argv[]) {
    typedef void (ProcessDataFunc)();

    HMODULE libHandle = LoadLibraryA("lib.dll"); // Load the library
    if (libHandle != NULL) {
        ProcessDataFunc* loop = (ProcessDataFunc*)GetProcAddress(libHandle, "loop");
        if (loop != NULL) {
            std::cout << "in\n";
            loop(); // Call the function
        } else {
            DWORD errorCode = GetLastError();
            LPSTR errorMessage = nullptr;
            FormatMessageA(
                FORMAT_MESSAGE_ALLOCATE_BUFFER | FORMAT_MESSAGE_FROM_SYSTEM | FORMAT_MESSAGE_IGNORE_INSERTS,
                nullptr,
                errorCode,
                MAKELANGID(LANG_NEUTRAL, SUBLANG_DEFAULT),
                reinterpret_cast<LPSTR>(&errorMessage),
                0,
                nullptr
            );

            std::cout << "Error obtaining function pointer: " << errorMessage << std::endl;

            LocalFree(errorMessage);
        }
    } else {
        std::cout << "Error loading library" << std::endl;
    }

    if (libHandle != NULL) {
        FreeLibrary(libHandle); // Free the library
    }

    return 0;
}
```

In this updated example, if `GetProcAddress` returns `NULL`, `GetLastError` is used to retrieve the error code. Then, `FormatMessage` is called to format the error message associated with the error code. The error message is printed to provide more information about the failure to obtain the function pointer.

Remember to include the necessary header files (`<windows.h>`, `<iostream>`) and to link against the appropriate libraries when compiling your program on Windows.
